let timer = null;
let element = null;
let dotNetRef = null;
let timeoutMs = 0;
let isIdle = false;

const events = ['mousemove', 'keydown', 'click', 'scroll', 'touchstart'];

function onActivity() {
    if (isIdle) {
        isIdle = false;
        dotNetRef.invokeMethodAsync('OnUserActive');
    }
    resetTimer();
}

function resetTimer() {
    if (timer !== null) {
        clearTimeout(timer);
    }
    timer = setTimeout(() => {
        isIdle = true;
        dotNetRef.invokeMethodAsync('OnUserIdle');
    }, timeoutMs);
}

export function initialize(el, ref, timeout) {
    element = el;
    dotNetRef = ref;
    timeoutMs = timeout;
    isIdle = false;

    events.forEach(evt => element.addEventListener(evt, onActivity, { passive: true }));
    resetTimer();
}

export function dispose() {
    if (timer !== null) {
        clearTimeout(timer);
        timer = null;
    }
    if (element) {
        events.forEach(evt => element.removeEventListener(evt, onActivity));
        element = null;
    }
    dotNetRef = null;
}

